#include <stdio.h>

long long calculateWaysToClimb(int totalSteps) {
    long long a = 1; // ways for 1 step
    long long b = 2; // ways for 2 steps
    if (totalSteps == 1) return a;
    if (totalSteps == 2) return b;
    long long cur = 0;
    for (int i = 3; i <= totalSteps; ++i) {
        cur = a + b;
        a = b;
        b = cur;
    }
    return b;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int totalSteps;
        scanf("%d", &totalSteps);
        printf("%lld\n", calculateWaysToClimb(totalSteps));
    }
    return 0;
}

