import sys

def calculateWaysToClimb(totalSteps: int) -> int:
    a, b = 1, 2
    if totalSteps == 1:
        return a
    if totalSteps == 2:
        return b
    for _ in range(3, totalSteps + 1):
        a, b = b, a + b
    return b

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        totalSteps = int(data[idx])
        idx += 1
        out.append(str(calculateWaysToClimb(totalSteps)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

